import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill } from "../types";

const SYSTEM_INSTRUCTION = `
You are the DukaanMitra AI Parsing Engine. 
Your job is to extract billing information from Hinglish (Hindi + English) WhatsApp messages sent by Kirana shop owners.

Input format examples:
- "Ram ne 2kg cheeni 150 rupaye ki li" -> { "customer_name": "Ram", "amount": 150, "items": "2kg cheeni" }
- "Aman 500 doodh cheeni" -> { "customer_name": "Aman", "amount": 500, "items": "doodh cheeni" }
- "Rahul 100 chai" -> { "customer_name": "Rahul", "amount": 100, "items": "chai" }

Rules:
1. Always return valid JSON.
2. amount must be a number.
3. confidence_score should be between 0 and 1 based on how clear the input is.
4. If the message doesn't look like a bill, set confidence_score < 0.5.
`;

export const parseMessage = async (text: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            customer_name: { type: Type.STRING },
            amount: { type: Type.NUMBER },
            items: { type: Type.STRING },
            confidence_score: { type: Type.NUMBER }
          },
          required: ["customer_name", "amount", "items", "confidence_score"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      customer_name: "Error",
      amount: 0,
      items: "Failed to parse",
      confidence_score: 0
    };
  }
};

