import React, { useState, useRef, useEffect } from 'react';
import { parseMessage } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  logs, setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; status?: string }[]>([
    { sender: 'bot', text: "Namaste! DukaanMitra CRM me aapka swagat hai. Aaj se aapke sabhi hisaab yahan safe rahenge. Message format: 'Aman 500 doodh cheeni'." }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chatHistory]);

  const handleSendMessage = async () => {
    if (!message.trim() || isProcessing) return;

    const userMsg = message.trim();
    setMessage("");
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg }]);
    setIsProcessing(true);

    // 1. Check user exists
    const mockUserPhone = "919876543210"; // Hardcoded for simulator simplicity
    const existingUser = customers.find(c => c.phone === mockUserPhone);

    // Simulating Make.com Orchestration Delay
    await new Promise(res => setTimeout(res, 800));

    // 2. AI Parsing using Gemini
    const result = await parseMessage(userMsg);

    if (result.confidence_score >= 0.7) {
      // Logic from Scenario 1
      const newTransId = `uuid-${Date.now()}`;
      const newTrans: Transaction = {
        transId: newTransId,
        phone: mockUserPhone,
        customerName: result.customer_name,
        amount: result.amount,
        items: result.items,
        date: new Date().toISOString()
      };

      setTransactions(prev => [...prev, newTrans]);

      // Update Customer LTV if they exist
      if (existingUser) {
        setCustomers(prev => prev.map(c => 
          c.phone === mockUserPhone 
            ? { ...c, totalLTV: c.totalLTV + result.amount } 
            : c
        ));
      }

      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: `Bil Update:\nCustomer: ${result.customer_name}\nAmount: ₹${result.amount}\nItems: ${result.items}\nHisaab confirm ho gaya hai! ✅` 
      }]);
    } else {
      // Failure Handling from Section 7
      setLogs(prev => [...prev, {
        timestamp: new Date().toISOString(),
        errorSource: "AI Parser",
        payloadReceived: JSON.stringify({ text: userMsg }),
        resolution: "Confidence score low. Error template sent."
      }]);

      setChatHistory(prev => [...prev, { 
        sender: 'bot', 
        text: "Maaf kijiye, humein samajh nahi aaya. Kripya is tarah likhein: 'Naam Amount Samaan'. Example: 'Rahul 100 chai'." 
      }]);
    }

    setIsProcessing(false);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-[calc(100vh-12rem)]">
      {/* Phone Simulator */}
      <div className="lg:col-span-1 bg-slate-900 rounded-[3rem] p-4 shadow-2xl border-[12px] border-slate-800 relative flex flex-col h-full overflow-hidden">
        {/* Notch */}
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-6 bg-slate-800 rounded-b-2xl z-20"></div>

        {/* Chat Area */}
        <div className="flex-1 bg-slate-100 rounded-[2rem] overflow-hidden flex flex-col mt-2">
          {/* Header */}
          <div className="bg-emerald-600 text-white p-4 pt-8 flex items-center space-x-3">
            <div className="w-10 h-10 bg-emerald-500 rounded-full flex items-center justify-center font-bold">DM</div>
            <div>
              <p className="font-bold text-sm">DukaanMitra AI</p>
              <p className="text-[10px] opacity-80">Online | Business Account</p>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-[#e5ddd5]">
            {chatHistory.map((chat, i) => (
              <div key={i} className={`flex ${chat.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-lg text-sm shadow-sm whitespace-pre-wrap ${
                  chat.sender === 'user' 
                    ? 'bg-[#dcf8c6] text-slate-800 rounded-tr-none' 
                    : 'bg-white text-slate-800 rounded-tl-none'
                }`}>
                  {chat.text}
                </div>
              </div>
            ))}
            {isProcessing && (
              <div className="flex justify-start">
                <div className="bg-white text-slate-400 p-2 rounded-lg text-xs animate-pulse">Typing...</div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 bg-slate-50 border-t flex space-x-2">
            <input 
              type="text" 
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Type message..."
              className="flex-1 bg-white border rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handleSendMessage}
              disabled={isProcessing}
              className="bg-emerald-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-emerald-700 transition disabled:opacity-50"
            >
              ➔
            </button>
          </div>
        </div>
      </div>

      {/* Logic Explained Panel */}
      <div className="lg:col-span-2 space-y-6 overflow-y-auto">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
          <h3 className="text-xl font-bold mb-4 flex items-center space-x-2">
            <span>⚙️</span>
            <span>Make.com Execution Engine (Simulated)</span>
          </h3>
          <div className="space-y-4">
            <div className="flex items-start space-x-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">A</div>
              <div>
                <p className="font-bold text-slate-900">Webhook Trigger</p>
                <p className="text-sm text-slate-500">Captured raw JSON from Gupshup API.</p>
              </div>
            </div>
            <div className={`flex items-start space-x-3 p-4 rounded-xl border transition-all ${isProcessing ? 'bg-amber-50 border-amber-200' : 'bg-slate-50 border-slate-100'}`}>
              <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">B</div>
              <div>
                <p className="font-bold text-slate-900">AI Parsing Node (Gemini-3-Flash)</p>
                <p className="text-sm text-slate-500">Extracting: Name, Amount, Items from natural language.</p>
              </div>
            </div>
            <div className="flex items-start space-x-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold">C</div>
              <div>
                <p className="font-bold text-slate-900">Google Sheet Update</p>
                <p className="text-sm text-slate-500">Appending to Transactions & Updating Customer LTV.</p>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-emerald-900 text-white p-6 rounded-2xl shadow-xl overflow-hidden relative">
          <div className="relative z-10">
            <h3 className="text-xl font-bold mb-2">MVP Debug Console</h3>
            <p className="text-emerald-300 text-sm mb-4">View real-time object state during transaction processing.</p>
            <div className="bg-emerald-950 p-4 rounded-lg font-mono text-[10px] h-48 overflow-y-auto">
              <pre className="text-emerald-400">
                {`// LAST AI EXTRACTION\n`}
                {JSON.stringify(chatHistory.filter(c => c.sender === 'bot').slice(-1)[0] || {}, null, 2)}
              </pre>
              <pre className="text-emerald-400 mt-4">
                {`// SYSTEM CONTEXT\n`}
                {JSON.stringify({
                  totalTransactions: transactions.length,
                  activeCustomers: customers.length,
                  isBotPaused: false
                }, null, 2)}
              </pre>
            </div>
          </div>
          {/* Subtle decoration */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-800 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 opacity-30"></div>
        </div>
      </div>
    </div>
  );
};

export default Simulator;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import SystemLogs from './components/SystemLogs';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');

  // App state simulating the Google Sheets database
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'customers':
        return <CustomerList customers={customers} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
    </Layout>
  );
};

export default App;

