import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import SystemLogs from './components/SystemLogs';
import DeploymentGuide from './components/DeploymentGuide';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('dashboard');

  // App state simulating the Google Sheets database
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'customers':
        return <CustomerList customers={customers} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'deployment':
        return <DeploymentGuide />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
    </Layout>
  );
};

export default App;
